        try:
            token = auth_header.split()[1]
            payload = verify_token(token, 'secret_key_here', ['HS256', 'RS256'])
            kwargs['current_user'] = payload
            return f(*args, **kwargs)
        except Exception as e:
            print(f"Error authenticating: {str(e)}")
